from functools import lru_cache

def solve(n: int, k: int) -> int:
    @lru_cache(maxsize=None)
    def popcount(x: int) -> int:
        count = 0
        while x:
            x &= x - 1
            count += 1
        return count

    @lru_cache(maxsize=None)
    def get_depth(x: int) -> int:
        if x == 1:
            return 0
        current = popcount(x)
        depth = 1
        while current != 1:
            current = popcount(current)
            depth += 1
            if depth > 60:
                return -1  # Prevent infinite loop for very large numbers
        return depth

    count = 0
    for i in range(1, n + 1):
        if get_depth(i) == k:
            count += 1
    return count
